SELECT DISTINCT ?actress ?actressLabel WHERE {
  wd:Q83410 wdt:P161 ?film .
  ?film wdt:P577 ?releaseDate .
  FILTER ( ?releaseDate >= "1940-01-01"^^xsd:date &&
           ?releaseDate < "1950-01-01"^^xsd:date )
  ?film wdt:P161 ?actress .
  ?actress wdt:P21 wd:Q6581072 .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[en]". }
}

SELECT DISTINCT ?actress ?actressLabel WHERE {
  ?film wdt:P364 wd:Q83410 ;
        wdt:P577 ?releaseDate .
  FILTER ( ?releaseDate >= "1940-01-01"^^xsd:date && ?releaseDate < "1950-01-01"^^xsd:date )
